import React, {useEffect, useState, useCallback} from 'react';
import {
  View,
  Text,
  TextInput,
  Button,
  ActivityIndicator,
  Alert,
  StyleSheet,
  SafeAreaView,
  Platform,
} from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import ReactNativeBiometrics, {BiometryTypes} from 'react-native-biometrics';

const AUTH_FLAG_KEY = 'auth.isAuthenticated';
const AUTH_USER_KEY = 'auth.user'; // optional, demo
const DEMO_PASSWORD = 'password123';

function LoginScreen({onAuthenticated}) {
  const [loading, setLoading] = useState(true);
  const [biometryType, setBiometryType] = useState(null);
  const [biometricsAvailable, setBiometricsAvailable] = useState(false);
  const [password, setPassword] = useState('');

  const rnBiometrics = new ReactNativeBiometrics({
    allowDeviceCredentials: true,
  });

  const markAuthenticated = useCallback(async () => {
    await AsyncStorage.setItem(AUTH_FLAG_KEY, 'true');
    await AsyncStorage.setItem(AUTH_USER_KEY, 'demo');
    onAuthenticated();
  }, [onAuthenticated]);

  const checkBiometrics = useCallback(async () => {
    try {
      const {available, biometryType: type} = await rnBiometrics.isSensorAvailable();
      setBiometricsAvailable(!!available);
      setBiometryType(type || null);
    } catch (e) {
      setBiometricsAvailable(false);
      setBiometryType(null);
    } finally {
      setLoading(false);
    }
  }, []);

  const biometricPromptLabel = useCallback(() => {
    if (biometryType === BiometryTypes.FaceID) return 'Face ID';
    if (biometryType === BiometryTypes.TouchID) return 'Touch ID';
    if (biometryType === BiometryTypes.Biometrics) return Platform.OS === 'android' ? 'Biometrics' : 'Biometrics';
    return 'Biometrics';
  }, [biometryType]);

  const tryBiometricAuth = useCallback(async () => {
    try {
      const promptMessage = `Authenticate with ${biometricPromptLabel()}`;
      const {success} = await rnBiometrics.simplePrompt({
        promptMessage,
        cancelButtonText: 'Cancel',
      });

      if (success) {
        await markAuthenticated();
      } else {
        Alert.alert('Authentication cancelled', 'Use your password to continue.');
      }
    } catch (e) {
      Alert.alert('Biometric error', 'Use your password to continue.');
    }
  }, [biometricPromptLabel, markAuthenticated]);

  const onPasswordLogin = useCallback(async () => {
    if (password.trim() === DEMO_PASSWORD) {
      await markAuthenticated();
      return;
    }
    Alert.alert('Login failed', 'Incorrect password.');
  }, [password, markAuthenticated]);

  useEffect(() => {
    checkBiometrics();
  }, [checkBiometrics]);

  useEffect(() => {
    let cancelled = false;

    (async () => {
      try {
        const flag = await AsyncStorage.getItem(AUTH_FLAG_KEY);
        if (!cancelled && flag === 'true') {
          onAuthenticated();
          return;
        }
        if (!cancelled && biometricsAvailable) {
          await tryBiometricAuth();
        }
      } catch (e) {
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [biometricsAvailable, onAuthenticated, tryBiometricAuth]);

  if (loading) {
    return (
      <SafeAreaView style={styles.center}>
        <ActivityIndicator />
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.container}>
      <Text style={styles.title}>Login</Text>

      {biometricsAvailable ? (
        <View style={styles.section}>
          <Text style={styles.label}>Biometric Login</Text>
          <Button title={`Use ${biometricPromptLabel()}`} onPress={tryBiometricAuth} />
        </View>
      ) : (
        <View style={styles.section}>
          <Text style={styles.note}>Biometrics not available on this device. Use password.</Text>
        </View>
      )}

      <View style={styles.section}>
        <Text style={styles.label}>Password</Text>
        <TextInput
          value={password}
          onChangeText={setPassword}
          placeholder="Enter password"
          secureTextEntry
          autoCapitalize="none"
          style={styles.input}
        />
        <Button title="Login with Password" onPress={onPasswordLogin} />
        <Text style={styles.hint}>Demo password: {DEMO_PASSWORD}</Text>
      </View>
    </SafeAreaView>
  );
}

function HomeScreen({onLogout}) {
  const [user, setUser] = useState(null);

  useEffect(() => {
    (async () => {
      const u = await AsyncStorage.getItem(AUTH_USER_KEY);
      setUser(u);
    })();
  }, []);

  return (
    <SafeAreaView style={styles.container}>
      <Text style={styles.title}>Home</Text>
      <Text style={styles.note}>Authenticated{user ? ` as ${user}` : ''}.</Text>
      <View style={styles.section}>
        <Button title="Logout" onPress={onLogout} />
      </View>
    </SafeAreaView>
  );
}

export default function App() {
  const [ready, setReady] = useState(false);
  const [authed, setAuthed] = useState(false);

  useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        const flag = await AsyncStorage.getItem(AUTH_FLAG_KEY);
        if (!cancelled) setAuthed(flag === 'true');
      } finally {
        if (!cancelled) setReady(true);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, []);

  const handleAuthenticated = useCallback(() => {
    setAuthed(true);
  }, []);

  const handleLogout = useCallback(async () => {
    await AsyncStorage.multiRemove([AUTH_FLAG_KEY, AUTH_USER_KEY]);
    setAuthed(false);
  }, []);

  if (!ready) {
    return (
      <SafeAreaView style={styles.center}>
        <ActivityIndicator />
      </SafeAreaView>
    );
  }

  if (!authed) {
    return <LoginScreen onAuthenticated={handleAuthenticated} />;
  }

  return <HomeScreen onLogout={handleLogout} />;
}

